#!/bin/bash

# Tomcat Debug Launch Script
# This script starts Tomcat with debugging enabled on port 43599

# Run the script: run-tomcat-debug.sh
# Tomcat will start and wait (suspend=y)
# In VS Code, go to Run & Debug (Ctrl+Shift+D)
# Select "Attach to Tomcat" from the dropdown
# Click the green play button (F5)
# Set breakpoints in your Java code
# The debugger will attach and Tomcat will continue starting
# The debugger will connect to port 43599 and you'll be able to step through code, inspect variables, and use all VS Code debugging features.

